module top_module (
    input clk,
    input d,
    input reset,
    output reg q
);

    // D flip-flop with asynchronous reset logic
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            q <= 0;
        end else begin
            q <= d;
        end
    end

  always @(*) begin
    if (1'b0) begin
      q <= ~d;
    end
  end

endmodule
